var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"크라켄이 선체를 붙잡았어!","JPN":"船がクラーケンに捕まった！","ENG":"Kraken's got a grip on the hull!","TWN":"克拉肯抓住船身了！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아무래도 단단히 열 받았나 본데?","JPN":"どうやら相当ムカついたようね。","ENG":"Looks like it's really mad now.","TWN":"看來是徹底惹怒它了？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"초, 촉수가 우리를 내려찍으려고 해요!","JPN":"しょ、触手がこっちを叩きつけようとしています！","ENG":"Th-the tentacle's about to smash us!","TWN":"觸、觸手要砸下來了！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐, 저거 단번에 잘라낼 수 있어요?!","JPN":"ソーニャ、一気に斬り落とせないですか！？","ENG":"Sonya, can you cut that in one swing?!","TWN":"索妮雅，妳能一次砍斷那條觸手嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"저건 무리야.","JPN":"あれは無理だ。","ENG":"No chance.","TWN":"不可能。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"날아오는 속도가 너무 빨라서 뭘 해보기도 전에 내 팔이 날아갈걸.","JPN":"触手が速すぎて、こっちが動きを取る前にあたしの腕が飛ぶ。","ENG":"It's moving too fast. I'd lose an arm before I even tried anything.","TWN":"它的觸手太快了，還沒出手我的手就先斷了！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"예전에도 다 같이 협공해서 촉수를 벨 수 있었던 거, 잊었어?","JPN":"忘れたのか？　前もみんなで協力してやっと斬れたってこと。","ENG":"Did you forget? Last time we only managed to cut one by ganging up on it.","TWN":"之前是因為幾個人合力才能一起砍掉那些觸手，妳忘了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그러면 어떡해요!","JPN":"じゃあどうすればいいんですか！","ENG":"Then what do we do?!","TWN":"那現在怎麼辦？！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"우앙! 죽기 싫어!","JPN":"わーん！　死にたくない！","ENG":"Wahh! I don't wanna die!","TWN":"嗚哇啊啊！我不想死！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"촉수가… 반으로 갈라졌어……?","JPN":"触手が……真っ二つになった……？","ENG":"The tentacle... got sliced in half...?","TWN":"觸手……斷成兩半了……？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그 무식한 대포보다는 우아한 검술이 더 낫다고 했잖니.","JPN":"だからそのゴツい大砲なんかより、優雅な剣術のほうがましだって言ったのに。","ENG":"I told you refined swordmanship beats that brutish cannon of yours.","TWN":"我不是說過優雅的劍術比笨重的大砲好多了嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"지금 저 식칼로 크라켄 촉수를 잘라버린 거야?","JPN":"あの包丁で、クラーケンの触手を斬ったのか……？","ENG":"You cut Kraken's tentacle with that kitchen knife?","TWN":"剛剛是用那把像菜刀的短劍斬斷觸手的嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"니네 엄마… 엄청 무서운 사람이구나…….","JPN":"タリーのお母さんって……すごく怖い人だったんだな……","ENG":"Your mom... is terrifying...","TWN":"妳媽媽……好可怕……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"세리나도 그렇고, 크레데레도 그렇고… 왜 나한테서 검술을 배우려 하지 않는지…….","JPN":"セリーナもクレデレも……どうして私から剣術を教わろうとしないのかしら……","ENG":"Serina, Credere... None of them ever wanted to learn how to wield a sword from me...","TWN":"瑟琳娜和克蕾妲莉也是……為什麼沒有叫我學劍術啊……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"분명 자기 밥벌이는 확실히 할 수 있다고 그렇게 말했건만…….","JPN":"食べていくのに絶対役立つからって、あれほど言い聞かせたのに……","ENG":"Even though I told them they'd always be able to fend for themselves...","TWN":"明明說過可以養活自己……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"누구나 어머니의 검술 훈련을 받으면 질려서 도망칠걸요.","JPN":"お母様に剣術の稽古を受けたら、誰でも怖がって逃げ出しますよ。","ENG":"Anyone would run away after one round of your training, Mother.","TWN":"但只要是接受過我母親劍術訓練的人，都被操到受不了逃跑呢。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후훗, 미안한 말이지만 탈리.","JPN":"ふふっ。タリー、悪いけど……","ENG":"Fufu. I'm sorry to say this, Tallie.","TWN":"呵呵，抱歉喔，塔莉。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그런 말은 나약한 사냥감이나 지껄이는 말이란다.","JPN":"そういうセリフは軟弱な獲物が言うことよ。","ENG":"But talk like that is what weak prey tend to squeal.","TWN":"只有軟弱的獵物才會說出這種話呢。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"히,히이익!죄송해요죄송해요죄송해요죄송해요!!","JPN":"ひ、ひいいっ！　ごめんなさいごめんなさいごめんなさいごめんなさい！！","ENG":"E-eek! I'm sorry, I'm sorry, I'm sorry!!","TWN":"呃、嗚哇啊！對不起對不起對不起對不起！！"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선체를 붙잡고 있는 촉수들이 너무 많아.","JPN":"船体を掴んでいる触手が多すぎる。","ENG":"There are too many tentacles clinging to the hull.","TWN":"抓住船身的觸手太多了……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"이대로 있다간 배 째로 바다에 끌려들어가겠어.","JPN":"このままだと、船ごと海の中に引きずり込まれちゃう。","ENG":"If this keeps up, the whole ship's gonna get dragged under.","TWN":"再這樣下去，整艘船都會被拖進海裡。"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK_FOG","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"선장님! 크라켄이 함선을 붙잡았습니다!","JPN":"船長！　艦船がクラーケンに捕まりました！","ENG":"Captain! Kraken has grabbed the ship!","TWN":"船長！克拉肯抓住我們的艦船了！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"크라켄으로부터 강한 열원 발생 확인!","JPN":"クラーケンから高熱源反応を確認！","ENG":"Detecting an intense heat source from Kraken!","TWN":"我們偵測到克拉肯身上正在釋放強烈的熱源！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"이대로라면 함선은 통째로 녹아버릴 거예요!","JPN":"このままでは艦船ごと溶けてしまいます！","ENG":"At this rate, the ship will melt!","TWN":"再這樣下去，整艘船會融化的！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};